    ('soldado-sampaio', 'PDL', '32', 2011, 'Declara de Utilidade Pública a Liga Roraimense de Direitos Humanos-LRDH e dá outras providências.', 'nao_informado', 'SAPL ALRR', 'RR-SAPL-9141', 'http://sapl.al.rr.leg.br/media/sapl/public/materialegislativa/2011/9141/pdl_032_2011.pdf', 'soldado-sampaio-rr-sapl-projetos-lei-ampliado-parcial-20260506', 'ampliado_parcial_soldado_sampaio_rr_sapl_dry_run_20260506', '{"source":"SAPL ALRR","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"coverage_id":"soldado-sampaio-rr-sapl-projetos-lei-ampliado-parcial-20260506","coverage_scope":"ampliado_parcial_soldado_sampaio_rr_sapl_dry_run_20260506","adapter_kind":"sapl_api","official_author_id":"64","official_materia_id":"9141","primeiro_autor":true,"crawl_date":"2026-05-07T02:20:55.410Z","data_real":true,"fluxo":"Legislacao full-site","curation_batch_id":"p0a1-state-assembly-lote-a-20260506","migration_version":"20260506233000","applied_by_migration":true,"dry_run_only":false,"data_apresentacao":"2011-10-25","official_detail_url":"https://sapl.al.rr.leg.br/api/materia/materialegislativa/9141/","official_author_url":"https://sapl.al.rr.leg.br/api/materia/autoria/?autor=64&page_size=100","public_url":"http://sapl.al.rr.leg.br/media/sapl/public/materialegislativa/2011/9141/pdl_032_2011.pdf","autoria_principal_verificada":true}'::jsonb)
) AS v(
  slug,
  tipo,
  numero,
  ano,
  ementa,
  situacao,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
);

DO $$
DECLARE
  duplicate_count int;
  target_with_other_coverage int;
  lme_target_coverage int;
BEGIN
  SELECT count(*) - count(DISTINCT slug || '|' || proposicao_id_api)
  INTO duplicate_count
  FROM _seed_p0a1_state_assembly_projetos;

  IF duplicate_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao P0-A1: seed contem % duplicatas slug/proposicao_id_api', duplicate_count;
  END IF;

  SELECT count(*)
  INTO target_with_other_coverage
  FROM projetos_lei pl
  JOIN candidatos c ON c.id = pl.candidato_id
  JOIN _seed_p0a1_state_assembly_projetos seed
    ON seed.slug = c.slug
   AND seed.proposicao_id_api = pl.proposicao_id_api
  WHERE pl.coverage_id IS NOT NULL
    AND pl.coverage_id <> seed.coverage_id;

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao P0-A1: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*)
  INTO lme_target_coverage
  FROM legislacao_mandato_executivo lme
  WHERE lme.metadata->>'coverage_id' IN (
    SELECT DISTINCT coverage_id FROM _seed_p0a1_state_assembly_projetos
  );

  IF lme_target_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao P0-A1: % rows LME usam coverage_id de projetos_lei alvo', lme_target_coverage;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id, c.slug
  FROM candidatos c
  WHERE c.slug IN (SELECT DISTINCT slug FROM _seed_p0a1_state_assembly_projetos)
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  situacao,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.situacao,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
JOIN _seed_p0a1_state_assembly_projetos seed ON seed.slug = target.slug
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  situacao = EXCLUDED.situacao,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  expected record;
  observed_count int;
  other_slugs_with_target int;
  lme_target_coverage int;
BEGIN
  FOR expected IN
    SELECT seed.slug, seed.coverage_id, seed.coverage_scope, count(*)::int AS expected_count
    FROM _seed_p0a1_state_assembly_projetos seed
    GROUP BY seed.slug, seed.coverage_id, seed.coverage_scope
  LOOP
    IF NOT EXISTS (SELECT 1 FROM candidatos c WHERE c.slug = expected.slug) THEN
      RAISE NOTICE 'P0-A1 %: candidato ausente neste banco local/CI minimo; pos-condicao pulada', expected.slug;
      CONTINUE;
    END IF;

    SELECT count(*)
    INTO observed_count
    FROM projetos_lei pl
    JOIN candidatos c ON c.id = pl.candidato_id
    WHERE c.slug = expected.slug
      AND pl.coverage_id = expected.coverage_id
      AND pl.coverage_scope = expected.coverage_scope;

    IF observed_count <> expected.expected_count THEN
      RAISE EXCEPTION 'Pos-apply P0-A1 %: esperadas % rows com coverage_id alvo, encontradas %',
        expected.slug, expected.expected_count, observed_count;
    END IF;
  END LOOP;

  SELECT count(*)
  INTO other_slugs_with_target
  FROM projetos_lei pl
  JOIN candidatos c ON c.id = pl.candidato_id
  WHERE pl.coverage_id IN (SELECT DISTINCT coverage_id FROM _seed_p0a1_state_assembly_projetos)
    AND NOT EXISTS (
      SELECT 1
      FROM _seed_p0a1_state_assembly_projetos seed
      WHERE seed.slug = c.slug
        AND seed.coverage_id = pl.coverage_id
    );

  IF other_slugs_with_target <> 0 THEN
    RAISE EXCEPTION 'Pos-apply P0-A1: % rows de outros slugs com coverage_id alvo', other_slugs_with_target;
  END IF;

  SELECT count(*)
  INTO lme_target_coverage
  FROM legislacao_mandato_executivo lme
  WHERE lme.metadata->>'coverage_id' IN (
    SELECT DISTINCT coverage_id FROM _seed_p0a1_state_assembly_projetos
  );

  IF lme_target_coverage <> 0 THEN
    RAISE EXCEPTION 'Pos-apply P0-A1: % rows LME usam coverage_id de projetos_lei alvo', lme_target_coverage;
  END IF;

  RAISE NOTICE 'P0-A1 state assembly projetos_lei apply OK: % rows alvo', (SELECT count(*) FROM _seed_p0a1_state_assembly_projetos);
END $$;
